class Solution:
    def largestOverlap(self, img1, img2):
        """
        :type img1: List[List[int]]
        :type img2: List[List[int]]
        :rtype: int
        """
        from collections import defaultdict

        # Get all 1-positions
        ones1 = [(i, j) for i in range(len(img1)) for j in range(len(img1[0])) if img1[i][j]]
        ones2 = [(i, j) for i in range(len(img2)) for j in range(len(img2[0])) if img2[i][j]]

        if not ones1 or not ones2:
            return 0

        # Count translation vectors
        translations = defaultdict(int)
        for i1, j1 in ones1:
            for i2, j2 in ones2:
                # Translation from (i2,j2) to (i1,j1)
                translations[(i1 - i2, j1 - j2)] += 1

        return max(translations.values())
